import { moduleMetadata } from '@storybook/angular';
import { PfSkeletonComponent } from './skeleton.component';
const meta = {
    title: 'Composants/Skeleton',
    component: PfSkeletonComponent,
    tags: ['autodocs'],
    parameters: {
        docs: {
            description: {
                component: "Placeholder animé (shimmer) pour indiquer un chargement. Décoratif (`aria-hidden`).",
            },
        },
    },
    decorators: [moduleMetadata({ imports: [PfSkeletonComponent] })],
    argTypes: {
        variant: { control: 'inline-radio', options: ['text', 'rect', 'circle'] },
    },
    args: { variant: 'rect', width: 200, height: 16 },
    render: (args) => ({
        props: args,
        template: `<pf-skeleton [variant]="variant" [width]="width" [height]="height"></pf-skeleton>`,
    }),
};
export default meta;
export const Text = {
    args: { variant: 'text', width: 240, height: '' },
};
export const Rectangle = {
    args: { variant: 'rect', width: 280, height: 120 },
};
export const Circle = {
    args: { variant: 'circle', width: 48, height: 48 },
};
export const ListItem = {
    render: () => ({
        template: `
      <div style="display: flex; flex-direction: column; gap: 16px; width: 360px;">
        @for (n of [1, 2, 3]; track n) {
          <div style="display: flex; align-items: center; gap: 12px;">
            <pf-skeleton variant="circle" [width]="40" [height]="40"></pf-skeleton>
            <div style="display: flex; flex-direction: column; gap: 6px; flex: 1;">
              <pf-skeleton variant="text" width="60%"></pf-skeleton>
              <pf-skeleton variant="text" width="90%"></pf-skeleton>
            </div>
          </div>
        }
      </div>
    `,
    }),
};
export const Card = {
    render: () => ({
        template: `
      <div style="width: 320px; display: flex; flex-direction: column; gap: 12px;">
        <pf-skeleton variant="rect" width="100%" [height]="160"></pf-skeleton>
        <pf-skeleton variant="text" width="80%" [height]="20"></pf-skeleton>
        <pf-skeleton variant="text" width="60%"></pf-skeleton>
        <pf-skeleton variant="text" width="90%"></pf-skeleton>
      </div>
    `,
    }),
};
